import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip
} from '@mui/material';
import {
  Close as CloseIcon,
  TrendingUp,
  TrendingDown,
  Refresh as RefreshIcon
} from '@mui/icons-material';

const ClosedOperationsModal = ({ open, onClose }) => {
  const [operations, setOperations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [apiData, setApiData] = useState(null);

  const loadClosedOperations = async () => {
    setLoading(true);
    setError(null);
    
    try {
      const response = await fetch('/api/dashboard/trades/closed', {
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      });

      if (!response.ok) {
        throw new Error(`Erro ${response.status}: ${response.statusText}`);
      }

      const data = await response.json();
      console.log('📊 Dados brutos da API:', data);
      
      setApiData(data);
      setOperations(data.trades || []);
      
    } catch (err) {
      console.error('❌ Erro ao carregar operações:', err);
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (open) {
      loadClosedOperations();
    }
  }, [open]);

  const formatCurrency = (value) => {
    if (value === null || value === undefined || value === '') return '-';
    const numValue = typeof value === 'string' ? parseFloat(value) : value;
    if (isNaN(numValue)) return '-';
    return numValue.toFixed(4);
  };

  const formatPercentage = (value) => {
    if (value === null || value === undefined || value === '') return '-';
    const numValue = typeof value === 'string' ? parseFloat(value) : value;
    if (isNaN(numValue)) return '-';
    return `${numValue.toFixed(2)}%`;
  };

  const formatLeverage = (value) => {
    if (value === null || value === undefined || value === '') return '1x';
    const numValue = typeof value === 'string' ? parseFloat(value) : value;
    if (isNaN(numValue)) return '1x';
    return `${Math.round(numValue)}x`;
  };

  const getSideColor = (side) => {
    return side?.toLowerCase() === 'long' ? 'success' : 'error';
  };

  const getPnlColor = (pnl) => {
    const numPnl = typeof pnl === 'string' ? parseFloat(pnl) : pnl;
    if (isNaN(numPnl) || numPnl === 0) return 'default';
    return numPnl > 0 ? 'success' : 'error';
  };

  const formatDate = (dateString) => {
    if (!dateString) return '-';
    try {
      const date = new Date(dateString);
      return date.toLocaleString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch {
      return '-';
    }
  };

  return (
    <Dialog 
      open={open} 
      onClose={onClose} 
      maxWidth="xl" 
      fullWidth
      PaperProps={{
        sx: { 
          minHeight: '80vh',
          backgroundColor: '#1a1a1a',
          color: 'white'
        }
      }}
    >
      <DialogTitle 
        sx={{ 
          backgroundColor: '#2d2d2d', 
          color: 'white',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center'
        }}
      >
        <Typography variant="h6" component="div">
          📈 Operações Encerradas
        </Typography>
        <Box sx={{ display: 'flex', gap: 1 }}>
          <Tooltip title="Atualizar dados">
            <IconButton 
              onClick={loadClosedOperations}
              disabled={loading}
              sx={{ color: 'white' }}
            >
              <RefreshIcon />
            </IconButton>
          </Tooltip>
          <IconButton 
            onClick={onClose}
            sx={{ color: 'white' }}
          >
            <CloseIcon />
          </IconButton>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ backgroundColor: '#1a1a1a', padding: 3 }}>
        {loading && (
          <Box display="flex" justifyContent="center" alignItems="center" minHeight="200px">
            <CircularProgress sx={{ color: '#4caf50' }} />
            <Typography variant="body1" sx={{ ml: 2, color: 'white' }}>
              Carregando operações...
            </Typography>
          </Box>
        )}

        {error && (
          <Alert 
            severity="error" 
            sx={{ mb: 2, backgroundColor: '#f44336', color: 'white' }}
          >
            Erro ao carregar dados: {error}
          </Alert>
        )}

        {!loading && !error && (
          <>
            {/* Debug Info */}
            <Box sx={{ mb: 3, p: 2, backgroundColor: '#2d2d2d', borderRadius: 1 }}>
              <Typography variant="h6" sx={{ color: '#4caf50', mb: 1 }}>
                🔍 Diagnóstico da API
              </Typography>
              <Typography variant="body2" sx={{ color: '#ccc' }}>
                Total de operações encontradas: {operations.length}
              </Typography>
              {apiData && (
                <Typography variant="body2" sx={{ color: '#ccc' }}>
                  Dados brutos: {JSON.stringify(apiData, null, 2).substring(0, 200)}...
                </Typography>
              )}
            </Box>

            {operations.length === 0 ? (
              <Box display="flex" justifyContent="center" alignItems="center" minHeight="200px">
                <Typography variant="h6" color="textSecondary">
                  🤷‍♂️ Nenhuma operação encerrada encontrada
                </Typography>
              </Box>
            ) : (
              <TableContainer 
                component={Paper} 
                sx={{ 
                  backgroundColor: '#2d2d2d',
                  maxHeight: '60vh',
                  overflow: 'auto'
                }}
              >
                <Table stickyHeader>
                  <TableHead>
                    <TableRow>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Símbolo
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Lado
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Tamanho
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Alavancagem
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Preço Entrada
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Preço Saída
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        PnL
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        ROE
                      </TableCell>
                      <TableCell sx={{ backgroundColor: '#3d3d3d', color: 'white', fontWeight: 'bold' }}>
                        Data Fechamento
                      </TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {operations.map((operation, index) => (
                      <TableRow 
                        key={operation.id || index}
                        sx={{ 
                          '&:nth-of-type(odd)': { backgroundColor: '#2a2a2a' },
                          '&:nth-of-type(even)': { backgroundColor: '#1f1f1f' },
                          '&:hover': { backgroundColor: '#404040' }
                        }}
                      >
                        <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>
                          {operation.symbol || '-'}
                        </TableCell>
                        
                        <TableCell>
                          <Chip
                            label={operation.side?.toUpperCase() || 'UNKNOWN'}
                            color={getSideColor(operation.side)}
                            size="small"
                            icon={operation.side?.toLowerCase() === 'long' ? <TrendingUp /> : <TrendingDown />}
                          />
                        </TableCell>
                        
                        <TableCell sx={{ color: 'white' }}>
                          {formatCurrency(operation.size)}
                        </TableCell>
                        
                        <TableCell sx={{ color: 'white' }}>
                          {formatLeverage(operation.leverage)}
                        </TableCell>
                        
                        <TableCell sx={{ color: 'white' }}>
                          ${formatCurrency(operation.entry_price)}
                        </TableCell>
                        
                        <TableCell sx={{ color: 'white' }}>
                          ${formatCurrency(operation.exit_price)}
                        </TableCell>
                        
                        <TableCell>
                          <Typography 
                            variant="body2" 
                            sx={{ 
                              color: getPnlColor(operation.pnl) === 'success' ? '#4caf50' : 
                                     getPnlColor(operation.pnl) === 'error' ? '#f44336' : 'white',
                              fontWeight: 'bold'
                            }}
                          >
                            ${formatCurrency(operation.pnl)}
                          </Typography>
                        </TableCell>
                        
                        <TableCell>
                          <Typography 
                            variant="body2" 
                            sx={{ 
                              color: getPnlColor(operation.roe) === 'success' ? '#4caf50' : 
                                     getPnlColor(operation.roe) === 'error' ? '#f44336' : 'white',
                              fontWeight: 'bold'
                            }}
                          >
                            {formatPercentage(operation.roe)}
                          </Typography>
                        </TableCell>
                        
                        <TableCell sx={{ color: '#ccc' }}>
                          {formatDate(operation.closed_at)}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>
            )}

            {/* Raw Data Debug Section */}
            {operations.length > 0 && (
              <Box sx={{ mt: 3, p: 2, backgroundColor: '#2d2d2d', borderRadius: 1 }}>
                <Typography variant="h6" sx={{ color: '#ff9800', mb: 1 }}>
                  🔧 Dados Brutos da Primeira Operação
                </Typography>
                <pre style={{ 
                  color: '#ccc', 
                  fontSize: '12px', 
                  overflow: 'auto',
                  maxHeight: '200px',
                  backgroundColor: '#1a1a1a',
                  padding: '10px',
                  borderRadius: '4px'
                }}>
                  {JSON.stringify(operations[0], null, 2)}
                </pre>
              </Box>
            )}
          </>
        )}
      </DialogContent>

      <DialogActions sx={{ backgroundColor: '#2d2d2d', padding: 2 }}>
        <Button 
          onClick={onClose} 
          variant="contained"
          sx={{ 
            backgroundColor: '#f44336',
            '&:hover': { backgroundColor: '#d32f2f' }
          }}
        >
          Fechar
        </Button>
        <Button 
          onClick={loadClosedOperations}
          variant="contained"
          disabled={loading}
          sx={{ 
            backgroundColor: '#4caf50',
            '&:hover': { backgroundColor: '#388e3c' }
          }}
        >
          Recarregar Dados
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default ClosedOperationsModal;
